import { OTPFieldPreview as OTPFieldPrimitive } from "@base-ui/react/otp-field";
import { createStyleContext } from "@/registry/bare/lib/create-style-context";
import { createPropSplitter } from "@/registry/bare/lib/split-variant-props";
import { otpFieldStyles } from "./styles";
import type { VariantProps } from "@/registry/bare/lib/tv.config";

type OTPFieldStyles = ReturnType<typeof otpFieldStyles>;
type OTPFieldVariantProps = VariantProps<typeof otpFieldStyles>;

const { StyleContext, useStyles } = createStyleContext<OTPFieldStyles>("OTPField");
const splitProps = createPropSplitter(otpFieldStyles);

export { useStyles as useOtpFieldStyles };

interface OTPFieldRootProps extends OTPFieldPrimitive.Root.Props, OTPFieldVariantProps {
  className?: string;
  styles?: OTPFieldStyles;
}

export function OTPFieldRoot(props: OTPFieldRootProps) {
  const [variantProps, { className, styles, ...htmlProps }] = splitProps(props);
  const s = styles ?? otpFieldStyles(variantProps);
  return (
    <StyleContext value={s}>
      <OTPFieldPrimitive.Root
        {...(htmlProps as OTPFieldPrimitive.Root.Props)}
        className={s.root({ class: className })}
        data-slot="otp-field"
      />
    </StyleContext>
  );
}

import { OTPFieldPreview as OTPFieldPrimitive } from "@base-ui/react/otp-field";
import { useOtpFieldStyles } from "./otp-field-root";

interface OTPFieldInputProps extends OTPFieldPrimitive.Input.Props {
  className?: string;
}

export function OTPFieldInput({ className, ...props }: OTPFieldInputProps) {
  const styles = useOtpFieldStyles();
  return (
    <OTPFieldPrimitive.Input
      {...props}
      className={styles.input({ class: className })}
      data-slot="otp-field-input"
    />
  );
}

import { OTPFieldPreview as OTPFieldPrimitive } from "@base-ui/react/otp-field";
import { useOtpFieldStyles } from "./otp-field-root";

interface OTPFieldSeparatorProps extends OTPFieldPrimitive.Separator.Props {
  className?: string;
}

export function OTPFieldSeparator({ className, ...props }: OTPFieldSeparatorProps) {
  const styles = useOtpFieldStyles();
  return (
    <OTPFieldPrimitive.Separator
      {...props}
      className={styles.separator({ class: className })}
      data-slot="otp-field-separator"
    />
  );
}

import { tv } from "@/registry/bare/lib/tv.config";

export const otpFieldStyles = tv({
  slots: {
    root: [""],
    input: [""],
    separator: [""],
  },
});

export { OTPFieldRoot as Root } from "./otp-field-root";
export { OTPFieldInput as Input } from "./otp-field-input";
export { OTPFieldSeparator as Separator } from "./otp-field-separator";
